var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"청소 끝!","JPN":"お掃除完了！","ENG":"Cleaning's done!","TWN":"清掃完畢！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"엣취!!","JPN":"はくしょん！！","ENG":"Ah-choo!","TWN":"哈啾！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 감기에 걸리셨나 보네요.","JPN":"レジーナ様、風邪をひいたようですね。","ENG":"You're coming down with a cold, Miss Regina.","TWN":"蕾佳娜大人，您好像感冒了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"마침 좋은 민간 요법이 있답니다.","JPN":"ちょうど良い民間療法があるんですよ。","ENG":"There's a good folk remedy for a cold.","TWN":"正好我這裡有很有效的民間療法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그래요? 그런 것도 당신이 말하는 지식에 속하나 보죠?","JPN":"そ、そうなんですか？　そういうのもあなたの言う知識の一部なんですか？","ENG":"R-really? Is it one of the pieces of knowledge you fed on?","TWN":"是，是嗎？這也屬於妳所說的知識嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 닭 지방을 목에 바른 다음 오래된 양말을 감아 두면 감기가 낫는다고 해요.","JPN":"ええ。鶏の脂肪を首に塗り、古い靴下を巻いておけば風邪が治るそうです。","ENG":"It is. You apply some chicken fat on your neck, then wrap an old sock around it.","TWN":"是的。據說，把雞油塗在脖子上，然後裹上舊襪子，感冒就會好起來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"닭은 없지만 침식체 것으로 대체해도 되지 않을까요?","JPN":"鶏はいないので、代わりに侵食体を使ってみてはどうです？","ENG":"We don't have chicken fat, but the fat of a Corrupted Object will work just fine.","TWN":"雖然這裡沒有雞，但用侵蝕體來代替應該也行吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사양하겠습니다. 전 그냥 아스피린이면 충분할 것 같아요.","JPN":"遠慮しておきます。私はアスピリンがあれば十分ですから。","ENG":"No, thank you. Just an aspirin would be fine for me.","TWN":"請容我拒絕。我吃阿司匹林就夠了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 것보다...... 하던 얘기를 마저 하고 싶어요.","JPN":"そんなことより……さっきの話の続きをしませんか？","ENG":"Anyway, let's get back to where we were, shall we?","TWN":"不說這些了……先講完剛才說的事情吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니의 시신은 대체 어디로 사라진 거죠?","JPN":"お母様の遺体はいったいどこへ消えたのです？","ENG":"Where did my mother's body go?","TWN":"母親的遺體究竟消失到哪裡去了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아지트를 샅샅이 찾아 봤지만 어머니의 시신은 없었어요.","JPN":"アジトを隅々まで探してみましたが、お母様の遺体はありませんでした。","ENG":"We rummaged through the hideout, but she wasn't there.","TWN":"我把基地到處都找了一遍，但沒有找到母親的遺體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"프리드웬 기관의 습격이니 뭐니 했던 이야기는 전부 거짓말이었나요?","JPN":"プリドウェン機関の襲撃だなんだという話は全部嘘だったのですか？","ENG":"Were all your stories about Prydwen Institution invading just lies?","TWN":"妳說什麼普利多溫機關的襲擊，這全是騙人的吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니면 그저......","JPN":"それとも、ただ……","ENG":"Did you just make me come...","TWN":"還是說，只是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그저 먹잇감을 잡아 줄 사람이 필요해서 절 꼬드겼던 건가요?","JPN":"ただ獲物を捕まえてくれる人が必要で、私を巻き込んだのですか？","ENG":"because you needed someone to prepare your meal?","TWN":"只是妳需要有人幫妳抓獵物，才唆使我這麼做的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"거짓말이 아니에요. 안나 맥크레디 부인의 시신은......","JPN":"嘘ではありません。アンナ・マクレディー夫人のご遺体は……","ENG":"They weren't lies. The body of your mother, Mrs. Anna MacCready was...","TWN":"這不是謊話，安娜·麥克蕾蒂夫人的遺體……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 숨기지 말고 솔직하게 얘기해 줘요.","JPN":"エデル、隠さず正直に言ってください。","ENG":"Edel, I want you to tell me everything, and I mean everything.","TWN":"艾瑟兒，不要隱瞞，老實告訴我吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 적어도 제가 여기서 왜 이러고 있는지는 알아야겠어요.","JPN":"私は少なくとも、自分がなぜここにいるのかを知る権利があると思うのですが。","ENG":"I have a right to know what I'm doing here with you.","TWN":"至少我該知道這裡到底發生什麼事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"직접 보신 것처럼 이 아이들은 더욱 많은 지식을 포식하기 위해 날뛰곤 해요.","JPN":"ご覧になったように、この子たちはより多くの知識を捕食するために暴れることがあります。","ENG":"As you saw, these babies can go into a frenzy out of their desire to prey on more knowledge.","TWN":"如您所見，這些孩子經常為了捕食更多知識而吵鬧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이 아이들을 완전히 통제할 수 있는 건 학회를 세운 에크하르트의 후손,","JPN":"この子たちを完全に統制できるのは学会を設立したエクハルトの子孫、","ENG":"And the only person in this world that can keep them under complete control is a descendent of Eckhart, the founder of the Society.","TWN":"能完全控制這些孩子的，只有學會建立者埃克哈特的子孫，"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 가문의 정당한 후계자뿐이에요.","JPN":"マクレディー家の正当な後継者だけなのです。","ENG":"Which means, the rightful heir of the MacCready family.","TWN":"也就是麥克蕾蒂家族的正統繼承人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 이번에는 후계자가 제때 준비되지 않았죠.","JPN":"ですが、今回は後継者の準備ができていませんでした。","ENG":"But this time, the heir wasn't with us when the time came.","TWN":"然而這次，繼承人並沒有適時做好準備。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 상황에서 프리드웬 기관까지 개입하는 바람에 실패하고 말았답니다.","JPN":"そのような状況でプリドウェン機関まで介入したせいで、失敗してしまったんです。","ENG":"And then Prydwen Institution jumped in, completely ruining the succession ceremony.","TWN":"在這種情況下，又有普利多溫機關的介入，導致轉移失敗。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그때 미처 옮기지 못한 아이들이 부인의 몸을 차지해서 날뛰고 있는 거예요.","JPN":"あの時に移しきれなかった子たちが夫人の体を操って暴れているのでしょう。","ENG":"So the babies that were supposed to have been transferred still remain in your mother's body, causing all this trouble.","TWN":"那時，尚未轉移的孩子們佔據了夫人的身體，大鬧了起來。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 아지트에서 본 참상도, 우릴 노리던 괴물들도.....","JPN":"では、アジトで見た惨状も、私たちを狙っていた怪物たちも……","ENG":"Then that horrific scene at the hideout, and the monsters that came after us...","TWN":"妳是說，我們在基地看到的慘像，還有盯上我們的那些怪物……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전부 어머니가 저지른 짓이란 말인가요?","JPN":"すべてお母様の仕業だということですか？","ENG":"Are you saying all this was my mother's doing?","TWN":"都是母親做的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇지 않아요. 부인께서는 이미 명을 달리하셨을 테니까요.","JPN":"そうではありません。夫人はすでに亡くなられていますから。","ENG":"No. Mrs. MacCready has already passed away.","TWN":"不是那樣的。夫人已經去世了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"부인 몸에 남겨진 건 학회에서도 오랫동안 금기시해 왔던 지식을 지닌 아이들이에요.","JPN":"夫人の体に残っていたのは、学会でも長く禁忌としていた知識を持つ子たちなんです。","ENG":"What's left in her body are the ones that hold the bits of knowledge that have been prohibited even in the Society.","TWN":"殘留在夫人身體的，是有著連學會都長年視為禁忌知識的孩子們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이대로 내버려 두면, 허기를 달래기 위해 무분별하게 지식을 탐식하고 다닐 거예요.","JPN":"このまま放っておけば、飢えを満たすために無差別に知識を食い荒らすようになるでしょう。","ENG":"If we let them be, all hell will break loose by their indiscreet craving for knowledge,","TWN":"就這樣放著不管的話，它們會為了填飽肚子，無差別地貪食知識。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이런 잔해들을 남기고 다니면서...... 앞으로도 계속.","JPN":"このような残骸を残しながら……これからもずっと。","ENG":"leaving these disasters behind, until someone stops them.","TWN":"留下這樣的殘骸……之後也會一直吃下去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"받아들이기 어려우실 것 같아서 먼저 말씀 드리지 못했어요. 죄송해요.","JPN":"なかなか受け入れられることではないので、前もってお伝えできませんでした。すみません。","ENG":"We wanted to tell you, but we thought it'd be too much for you to process. Sorry.","TWN":"我們想您應該很難接受這件事，所以沒有一開始就告訴您，非常抱歉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 배려해 달라고 부탁한 적 없어요.","JPN":"私は気遣ってほしいと頼んだことなどないはずです。","ENG":"I didn't ask for your consideration.","TWN":"我從沒有拜託妳顧慮我。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다들 제정신이 아니에요. 그깟 괴물 따위 내버려 두면 되잖아요.","JPN":"皆、正気ではありませんね。たかが怪物など、放置しておけばいいのですよ。","ENG":"All of you are just insane. Why can't you just leave the monsters alone then?","TWN":"大家太不正常了。那種怪物什麼的，放著不管不就好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐가 아쉬워서 자기 몸을 내 주죠? 대체 학회가 뭐라고......!","JPN":"どうして自分の体を差し出さないといけないのです？　学会なんかのために……！","ENG":"I can't believe you're mad enough to offer your body to them! What purpose could the Society possibly serve by its existence?","TWN":"有什麼好可惜的，非要把它們放進自己身體不可？學會到底是什麼東西啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"예전에 부인께서 가르쳐 주시지 않았던가요?","JPN":"以前、夫人から教わりませんでしたか？","ENG":"Didn't Mrs. MacCready tell you?","TWN":"夫人以前沒有告訴過您嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"학회란...... 지식을 탐식하는 호수를 위해 먹잇감을 찾는 자들이라는 걸.","JPN":"学会というのは……知識を食らう湖のための餌を探す者たちだということを。","ENG":"The Society is a group of hunters looking for prey to be offered to the knowledge-grubbing Lake.","TWN":"學會……就是指為了貪食知識之湖而尋找獵物的人們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};